import { GoogleMap, LoadScript, StandaloneSearchBox, Marker, InfoWindow } from '@react-google-maps/api';
import { useRef, useState, useCallback } from 'react';
import axios from 'axios';

const mapContainerStyle = {
  width: '100vw',
  height: '100vh'
};

const defaultCenter = {
  lat: 37.7749,
  lng: -122.4194
};

const libraries = ["places"];

function App() {
  const [center, setCenter] = useState(defaultCenter);
  const [apartments, setApartments] = useState([]);
  const [selectedApartment, setSelectedApartment] = useState(null);
  const [summary, setSummary] = useState('');
  const [loading, setLoading] = useState(false);
  const searchBox = useRef(null);
  const mapRef = useRef(null);

  const onMapLoad = useCallback((map) => {
    mapRef.current = map;
  }, []);

  const searchApartments = (location) => {
    const service = new window.google.maps.places.PlacesService(mapRef.current);
    const request = {
      location: location,
      radius: 5000,
      keyword: 'apartment complex'
    };

    service.nearbySearch(request, (results, status) => {
      if (status === window.google.maps.places.PlacesServiceStatus.OK) {
        setApartments(results);
      }
    });
  };

  const onPlacesChanged = () => {
    const places = searchBox.current.getPlaces();
    if (places && places.length > 0) {
      const place = places[0];
      const newCenter = {
        lat: place.geometry.location.lat(),
        lng: place.geometry.location.lng()
      };
      setCenter(newCenter);
      searchApartments(place.geometry.location);
    }
  };

  const handleMarkerClick = (apartment) => {
    setSelectedApartment(apartment);
    setSummary('');
    setLoading(true);

    const service = new window.google.maps.places.PlacesService(mapRef.current);
    service.getDetails(
      { placeId: apartment.place_id, fields: ['reviews', 'name'] },
      async (place, status) => {
        if (status === window.google.maps.places.PlacesServiceStatus.OK && place.reviews) {
          const reviewText = place.reviews.map(r => r.text).join('\n\n');
          try {
            const response = await axios.post('http://localhost:3001/api/summarize', {
              reviews: reviewText,
              apartmentName: place.name
            });
            setSummary(response.data.summary);
          } catch (error) {
            setSummary('Could not load summary.');
          }
        } else {
          setSummary('No reviews available for this location.');
        }
        setLoading(false);
      }
    );
  };

  return (
    <LoadScript googleMapsApiKey="AIzaSyBGNDvvjBWtpAWZXtTnTEWgJ0sYigcrW0g" libraries={libraries}>
      <div style={{ position: 'relative' }}>
        <StandaloneSearchBox
          onLoad={(ref) => (searchBox.current = ref)}
          onPlacesChanged={onPlacesChanged}
        >
          <input
            type="text"
            placeholder="Search a city or neighborhood..."
            style={{
              position: 'absolute',
              top: '20px',
              left: '50%',
              transform: 'translateX(-50%)',
              width: '400px',
              padding: '12px',
              zIndex: 10,
              borderRadius: '8px',
              border: 'none',
              boxShadow: '0 2px 10px rgba(0,0,0,0.3)',
              fontSize: '16px'
            }}
          />
        </StandaloneSearchBox>
        <GoogleMap
          mapContainerStyle={mapContainerStyle}
          center={center}
          zoom={13}
          mapTypeId="hybrid"
          onLoad={onMapLoad}
        >
          {apartments.map((apartment) => (
            <Marker
              key={apartment.place_id}
              position={{
                lat: apartment.geometry.location.lat(),
                lng: apartment.geometry.location.lng()
              }}
              label={{
                text: apartment.rating ? `★ ${apartment.rating}` : '?',
                color: 'white',
                fontWeight: 'bold',
                fontSize: '12px'
              }}
              onClick={() => handleMarkerClick(apartment)}
            />
          ))}

          {selectedApartment && (
            <InfoWindow
              position={{
                lat: selectedApartment.geometry.location.lat(),
                lng: selectedApartment.geometry.location.lng()
              }}
              onCloseClick={() => setSelectedApartment(null)}
            >
              <div style={{ maxWidth: '300px', padding: '10px' }}>
                <h3 style={{ margin: '0 0 8px 0' }}>{selectedApartment.name}</h3>
                <p style={{ margin: '0 0 8px 0' }}>⭐ {selectedApartment.rating} / 5</p>
                {loading ? (
                  <p>Loading AI summary...</p>
                ) : (
                  <pre style={{ whiteSpace: 'pre-wrap', fontFamily: 'inherit', fontSize: '13px' }}>
                    {summary}
                  </pre>
                )}
              </div>
            </InfoWindow>
          )}
        </GoogleMap>
      </div>
    </LoadScript>
  );
}

export default App;
